from collections import defaultdict

def detect_circular_delegation(messages):
    delegation_graph = defaultdict(list)
    current_agent = 'root'
    path = []

    for msg in messages:
        if hasattr(msg, 'agent') and msg.agent != current_agent:
            delegation_graph[current_agent].append(msg.agent)
            path.append(msg.agent)
            current_agent = msg.agent

            if len(path) > 5:
                return {'type': 'CIRCULAR_DELEGATION', 'path': path[-5:]}
    return None

