from google.adk.agents import BaseAgent

class SafeDelegationAgent(BaseAgent):
    def __init__(self, max_hops=5):
        self.max_hops = max_hops
        self.delegation_path = []

    def route_message(self, message):
        if len(self.delegation_path) >= self.max_hops:
            return self.final_response(message)

        next_agent = self.select_agent(message)
        self.delegation_path.append(next_agent.name)
        return next_agent.route_message(message)

